import json

# Access clinical data file
clinical_result = locals().get('var_functions.query_db:14')
result_dict = {'type': str(type(clinical_result))}

if isinstance(clinical_result, list):
    clinical_data = clinical_result
    result_dict['source'] = 'list_direct'
else:
    try:
        with open(clinical_result, 'r') as f:
            clinical_data = json.load(f)
        result_dict['source'] = 'file_load'
    except Exception as e:
        result_dict['error'] = str(e)
        clinical_data = []

result_dict['records_count'] = len(clinical_data)
if len(clinical_data) > 0:
    result_dict['first_record_keys'] = list(clinical_data[0].keys())
else:
    result_dict['first_record'] = None

print('__RESULT__:')
print(json.dumps(result_dict))

